"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[4987],{2476:(D,B,p)=>{p.r(B),p.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-34dc378d","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%BA%D0%BE%D1%80%D0%BE%D0%B1%D0%BA%D0%BE%D0%B2%D0%B0-%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D0%B0-%D0%BD%D0%B5%D0%BA%D0%BE%D1%82%D0%BE%D1%80%D1%8B%D0%B5-%D1%84%D0%B0%D0%BA%D1%82%D1%8B-%D0%B8%D0%B7-%D0%B8%D1%81%D1%82%D0%BE%D1%80%D0%B8%D0%B8-%D1%81%D0%BE%D0%B7%D0%B4%D0%B0%D0%BD%D0%B8%D1%8F-%D0%B8-%D0%BF%D1%80%D0%B8%D0%BC%D0%B5%D0%BD%D0%B5%D0%BD%D0%B8%D1%8F-%D0%BC%D0%B0%D0%BB%D1%8B%D1%85.html","title":"Некоторые факты из истории создания и применения малых ЭВМ серии «МИР»","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1730914103000},"filePathRelative":"глушковские-чтения/коробкова-глушкова-некоторые-факты-из-истории-создания-и-применения-малых.md"}')},3148:(D,B,p)=>{p.r(B),p.d(B,{default:()=>r});var l=p(6252);const t=(0,l._)("h1",{id:"некоторые-факты-из-истории-создания-и-применения-малых-эвм-серии-«мир»",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#некоторые-факты-из-истории-создания-и-применения-малых-эвм-серии-«мир»","aria-hidden":"true"},"#"),(0,l.Uk)(" Некоторые факты из истории создания и применения малых ЭВМ серии «МИР»")],-1),i=(0,l._)("p",null,"Коробкова Т. В., Глушкова В. В.",-1),e=(0,l.uE)("<p>Важнейшим направлением в области развития архитектур ЭВМ в 60-х гг. прошлого столетия в Институте кибернетики АН УССР становится интеллектуализация ЭВМ.</p><p>Признание важности этого направления пришло в 1963 году на довольно узком симпозиуме, организованном Институтом кибрнетики и Ужгородским университетом, в котором участвовали Лебедев, Глушков, Сулим (будущий заместитель министра радиопромышленности, а в то время начальник главного управления вычислительной техники министерства) и др. В основном обсуждались киевские предложения по развитию архитектуры ЭВМ. Атмосфера была дружеская, а критика вполне доброжелательная. Обсуждение — деловым. В Ужгороде «высокие стороны» окончательно договорились о том, что Институт точной механики и вычислительной техники АН СССР по-прежнему будет заниматься проблемой создания супер-ЭВМ, а Институт кибернетики АН Украины — малыми и специализированными ЭВМ.</p><p>Возвратившись в Киев, В. М. Глушков энергично взялся за разработку ЭВМ МИР.</p><p>«Проектируя МИРы, мы поставили дерзкую задачу — сделать машинный язык возможно более близким к человеческому (имеется в виду математический, а не разговорный язык, хотя мы делали опыты и по созданию машин с нормальным человеческим языком). И такой язык «Аналитик» был создан и поддержан оригинальной внутримашинной системой его интерпретации. Машины МИР использовались во всех уголках Советского Союза. Их создание является промежуточным этапом развития работ по искусственному интеллекту»,— говорил Глушков в своих воспоминаниях [1].</p><p>В. М. Глушковым и руководимым им коллективом была проделана огромная работа по созданию ЭВМ нового типа. Машины серии МИР считаются сейчас прообразами современных персональных ЭВМ [2]. МИР-2 и МИР-3 стали самыми массовыми машинами для инженерных расчетов. ЭВМ серии МИР выполняли аналитические преобразования, в том числе дифференцирование и интегрирование.</p><p>В 1963 г. началась разработка малогабаритной вычислительной машины МИР-1, которая была предназначена для автоматизации вычислительных работ в научно-исследовательских и проектных организациях, с алгоритмическим языком АНАЛИТИК, максимально приближенным к привычному для инженеров и научных работников языку математики [2]. В 1964 г. разработка была закончена и ЭВМ МИР-1 была успешно сдана Госкомиссии в 1965 г.</p><p>В 1969 г. появилась более совершенная ЭВМ МИР-2, на которой впервые в практике отечественного математического машиностроения был реализован диалоговый режим работы, который использовал дисплей со световым пером [3]. В 1973 г. была закончена работа по созданию экспериментального комплекса технических и автоматических средств объединения МИР-2 и БЭСМ-6, особенностью которого было сочетание «интеллектуальных» возможностей МИР-2 с большими информационными мощностями и быстродействием БЭСМ-6.</p><p>В 1974 г. была завершена разработка и внедрена в производство новая ЭВМ серии МИР – МИР-3 с входным языком АНАЛИТИК-74. Машину отличали высокое быстродействие, совершенство структуры математических и технических средств, развитый входной язык для обеспечения диалога человека с машиной, совместимость с машинами ЕС ЭВМ и др. Это позволяло, наряду с традиционными областями применения машин такого класса, эффективно использовать ЭВМ МИР-3 в качестве интеллектуальных пультов и терминалов в программно-управляемых комплексах испытаний готовых объектов, автоматизированных системах проектирования, информационных системах, создаваемых на базе ЭВМ 3-го поколения. Машина позволяла осуществлять принципиально новые технологические процессы, инженерные расчеты, значительно расширяла круг задач, решаемых на ЭВМ МИР-1 и МИР-2.</p><p>Машины давали значительный экономический эффект. Киевским заводом ВУМ к 1970 г. было выпущено более 200 этих машин, годовой экономический эффект которых — 15,8 млн. руб. В 1974 г. предполагался ориентировочный экономический эффект до 100 тыс. руб. в год на каждой ЭВМ МИР-3.</p><p>В 1968 г. за разработку новых принципов построения структур малых машин для инженерных расчетов и математического обеспечения для них, внедренных в вычислительных машинах серии МИР, награждены Государственной премией СССР В. М. Глушков, Ю. В. Благовещенский, А. А. Летичевский, В. Д. Лосев, И. Н. Молчанов, С. Б. Погребинский, А. А. Стогний [3].</p><p>О большом научном значении и широком применении упомянутых машин свидетельствует создание Ассоциации пользователей ЭВМ серии МИР, которая была общественным, межведомственным, координирующим органом по вопросам математической и технической эксплуатации машин серии МИР. Ассоциация была создана приблизительно в 1970 г. и в нее вошло 102 организации из различных городов [4]. В 1971 г. в нее входило 400 организаций, в 1974 г.— свыше 600. В последние годы эксплуатации машин серии МИР в ассоциацию входило около 1100 организаций [5]. Ассоциацией проводилась большая научно-техническая работа. Например, в 1971 г. ассоциацией ежемесячно проводились однодневные семинары по инженерно-математической эксплуатации ЭВМ МИР в различных городах — Киеве, Москве, Ленинграде, Свердловске. Специалистами Института кибернетики был прочитан курс лекций по программированию на ЭВМ МИР в городах Новосибирске и Грозном. В г. Орджоникидзе ассоциациейбыл проведен семинар «Теория и практика программирования на ЭВМ МИР-1», на котором присутствовало 104 человека из 33 городов. Ассоциацией был переиздан набор программ для ЭВМ МИР-1 в 7 книгах, изданы сборник «Машины для инженерных расчетов» и два выпуска «Информационные материалы».</p><p>ЭВМ серии МИР постоянно демонстрировались на выставках и неоднократно награждались медалями и дипломами. В 1968 г. за работы по математическому обеспечению машин серии МИР В. М. Глушков был награжден золотой медалью ВДНХ, а другие участники работ по этой машине – одной серебряной и пятью бронзовыми медалями. В 1971 г. машина МИР-2 была удостоена диплома 1-й степени ВДНХ и ее разработчики награждены золотой, четырьмя серебряными и двадцатью бронзовыми медалями. В 1972 г. Институт кибернетики принимал участие в трех международных выставках («Биофизика-72», «Геронтология-72», Пловдивская ярмарка), в двух всесоюзных и в республиканской выставке, на которых демонстрировалась и ЭВМ МИР-2.</p><p>Работы по созданию ЭВМ серии МИР широко освещались в прессе. С 1965 г. по 1978 г. в республиканских и всесоюзных газетах и журналах было не менее 60 публикаций.</p><p>К сожалению, в конце 1970-х годов в связи с провозглашенной технической политикой перехода на машины серии ЕС (IВМ-360) прекратился многотысячный тираж машин серии МИР [2]. Но принципы, положенные в основу реализации ЭВМ серии МИР, не потеряли своего значения. В частности, ученики и последователи В. М. Глушкова(В. П. Клименко, А. Л. Ляхов, А. А. Морозов, Ю. С. Фишман, Т. Н. Швалюк) продолжили работу по развитию семейства языков АНАЛИТИК. Были разработаны АНАЛИТИК-79, АНАЛИТИК-89, АНАЛИТИК-91, АНАЛИТИК-93, АНАЛИТИК- 2000, АНАЛИТИК-2007 [6]. В 2010 г. опубликовано статью, в которой рассматривается новый этап развития системы компьютерной алгебры АНАЛИТИК – реинжиниринг на основе новых прогрессивных технологий [7].</p><p>Список источников</p><ol><li><p>Малиновский Б.Н. История вычислительной техники в лицах. - К.: фирма &quot;КИТ&quot;, ПТОО &quot;А.С.К.&quot;, 1995. - 384 с.</p></li><li><p>Клименко В.П., Фишман Ю.С.. Первые в мире персональные ЭВМ // Кибернетика и системный анализ. – 1993. – No 3. – с. 176-180.</p></li><li><p>Капитонова Ю.В., Летичевский А.А. Парадигмы и идеи академика В.М. Глушкова – К.: Наукова думка, 2003. –456 с.</p></li><li><p>Асоціація споживачів ЕОМ // Вечірній Київ. – 1970. –No 304.</p></li><li><p>Институт проблем математических машин и систем НАН Украины. 50 лет научной деятельности. – К., 2014. – 542 с.</p></li><li><p>Системы компьютерной алгебры семейства АНАЛИТИК. Теория. Реализация. Применение. – К., 2010. – 762 с.</p></li><li><p>Клименко В.П., Ляхов А.Л., Гвоздик Д.Н. Реинжиниринг системы компьютерной алгебры АНАЛИТИК. // Математичні машини і системи. – 2010. – No 4. – с. 18-23.</p></li><li><p>Морозов А.А., Глушкова В.В., Коробкова Т.В. Создание единой системы социальной информации (ЕССИ) – Болгарской ОГАС // Математичні машини і системи. – 2013. – No 3. – с. 3-21.</p></li></ol>",16),a={},r=(0,p(3744).Z)(a,[["render",function(D,B){const p=(0,l.up)("RouterLink");return(0,l.wg)(),(0,l.iD)("div",null,[t,i,(0,l._)("p",null,[(0,l.Uk)("Из материалов конференции "),(0,l.Wm)(p,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,l.w5)((()=>[(0,l.Uk)("«Глушковские чтения»")])),_:1}),(0,l.Uk)(" 2015 года.")]),e])}]])}}]);